  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `country_id` int(10) unsigned NOT NULL,
  `code` varchar(10) DEFAULT NULL,
  `name` varchar(255) DEFAULT NULL,
  `cname` varchar(255) DEFAULT NULL,
  `lower_name` varchar(255) DEFAULT NULL,
  `code_full` varchar(10) NOT NULL,
  `area_id` int(10) unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_area_state_code` (`code_full`),
  KEY `fk_area_state_city_country_id` (`country_id`),
  CONSTRAINT `fk_area_state_city_country_id` FOREIGN KEY (`country_id`) REFERENCES `area_country` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=270 DEFAULT CHARSET=utf8;
