--
-- Table structure for table `area_city`
--

DROP TABLE IF EXISTS `area_city`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `area_city` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `state_id` int(10) unsigned NOT NULL,
  `country_id` int(10) unsigned NOT NULL,
  `country_code` varchar(10) NOT NULL,
  `code` varchar(10) NOT NULL,
  `name` varchar(255) DEFAULT NULL,
  `cname` varchar(255) DEFAULT NULL,
  `lower_name` varchar(255) DEFAULT NULL,
  `code_full` varchar(10) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_area_city_code` (`code_full`),
  KEY `area_city_code` (`country_code`,`code`),
  KEY `fk_area_city_area_country_id` (`country_id`),
  KEY `fk_area_city_area_state_id` (`state_id`),
  CONSTRAINT `fk_area_city_area_country_code` FOREIGN KEY (`country_code`) REFERENCES `area_country` (`code`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `fk_area_city_area_country_id` FOREIGN KEY (`country_id`) REFERENCES `area_country` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `fk_area_city_area_state_id` FOREIGN KEY (`state_id`) REFERENCES `area_state` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=3798 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

